// Er-Tech Iletisim — PDF font paketi (v278)
// 1) Roboto  : Turkce metin (alt-kumelenmis, ~16 KB)
//    v278: Roboto'da OLMAYAN ▲ ▼ ↑ ↓ ● ■ □ ◆ ✓ ✔ → ← glifleri DejaVu Sans'tan
//    birlestirildi. Bunlar tabloda "Fark" ve "Buyume" sutunlarinda kullaniliyor;
//    fontta bulunmadiklari icin PDF'te sessizce kayboluyorlardi.
// 2) NotoEmoji: tek renkli simgeler (alt-kumelenmis, 8 KB)
//
// jsPDF metni charCodeAt ile isler; 📦 gibi astral (>U+FFFF) simgeler vekil ciftine
// bolundugu icin cizilemez. Bu yuzden o glifler fontta Ozel Kullanim Alanina (U+E000+)
// yeniden eslendi. ERTECH_EMOJI haritasi gercek simgeyi PUA karakterine cevirir.
(function(){
  window.ERTECH_PDF_FONT = {
    regular: "",
    bold: "",
    emoji: ""
  };

  window.ERTECH_EMOJI = {
    "ℹ": "\u2139",
    "⏳": "\u23F3",
    "⚠": "\u26A0",
    "✅": "\u2705",
    "✏": "\u270F",
    "➡": "\u27A1",
    "⬅": "\u2B05",
    "🆕": "\uE000",
    "🎁": "\uE001",
    "💰": "\uE002",
    "💵": "\uE003",
    "📊": "\uE004",
    "📑": "\uE005",
    "📦": "\uE006",
    "🔄": "\uE007",
    "🔍": "\uE008",
    "🔒": "\uE009",
    "🧮": "\uE00A"
  };

  window.ertechFontKur = function(doc){
    try{
      doc.addFileToVFS('RobotoTR-Regular.ttf', window.ERTECH_PDF_FONT.regular);
      doc.addFont('RobotoTR-Regular.ttf', 'RobotoTR', 'normal');
      doc.addFileToVFS('RobotoTR-Bold.ttf', window.ERTECH_PDF_FONT.bold);
      doc.addFont('RobotoTR-Bold.ttf', 'RobotoTR', 'bold');
      doc.addFileToVFS('NotoEmojiTR.ttf', window.ERTECH_PDF_FONT.emoji);
      doc.addFont('NotoEmojiTR.ttf', 'EmojiTR', 'normal');
      doc.setFont('RobotoTR', 'normal');
      return true;
    }catch(e){
      console.warn('PDF fontlari yuklenemedi, helvetica kullanilacak:', e);
      return false;
    }
  };
})();
